"use strict";(self.webpackChunkportfolio=self.webpackChunkportfolio||[]).push([[5323],{5415:t=>{t.exports=JSON.parse('{"blogPosts":[{"id":"Introduction","metadata":{"permalink":"/portfolio/es/blog/Introduction","source":"@site/blog/2023-01-21-introduction/index.md","title":"Introduction","description":"I would like to take a coffe with you and sit to draw & think.","date":"2023-01-21T00:00:00.000Z","formattedDate":"21 de enero de 2023","tags":[],"readingTime":0.46,"hasTruncateMarker":false,"authors":[{"name":"Juan Carlos","title":"Arroyo Sosa","url":"https://github.com/jcarroyos","imageURL":"https://avatars.githubusercontent.com/u/4398275","key":"jcarroyos"}],"frontMatter":{"slug":"Introduction","title":"Introduction","authors":["jcarroyos"],"tags":[]},"nextItem":{"title":"Virtual enviroments at MMGP","permalink":"/portfolio/es/blog/virtual-enviroment-unal"}},"content":"I would like to take a coffe with you and sit to draw & think.\\n\\nLet me tell you that if I were to exhibit my last years works, it would undoubtedly be a exploration, an invitation to despertar your curiosity of information architectures, diagrams, data visualizations and user interfaces, with explanatory notes on complex social issues.\\n\\nThe hard work will be to remember all names of friends, physicists, economists, communicators, political scientists, sociologists, social leaders and human rights defenders with whom I have had the honor of sitting down to think."},{"id":"virtual-enviroment-unal","metadata":{"permalink":"/portfolio/es/blog/virtual-enviroment-unal","source":"@site/blog/2021-06-30-virtual-enviroment/index.md","title":"Virtual enviroments at MMGP","description":"How do museums take advantage of information technologies and virtual environments? Well, based on this question, a pedagogical experience was created for the fifth, sixth and seventh cohorts of the Master\'s Degree in Museology and Heritage Management at the National University of Colombia, the name of the course is, ... to no one\'s surprise \ud83d\ude0c, INFORMATION TECHNOLOGIES AND VIRTUAL ENVIRONMENTS.","date":"2021-06-30T00:00:00.000Z","formattedDate":"30 de junio de 2021","tags":[{"label":"tics","permalink":"/portfolio/es/blog/tags/tics"},{"label":"museology","permalink":"/portfolio/es/blog/tags/museology"}],"readingTime":0.615,"hasTruncateMarker":false,"authors":[{"name":"Juan Carlos","title":"Arroyo Sosa","url":"https://github.com/jcarroyos","imageURL":"https://avatars.githubusercontent.com/u/4398275","key":"jcarroyos"}],"frontMatter":{"slug":"virtual-enviroment-unal","title":"Virtual enviroments at MMGP","authors":["jcarroyos"],"tags":["tics","museology"]},"prevItem":{"title":"Introduction","permalink":"/portfolio/es/blog/Introduction"},"nextItem":{"title":"Infographics at UTolima","permalink":"/portfolio/es/blog/infographics-utolima"}},"content":"How do museums take advantage of information technologies and virtual environments? Well, based on this question, a pedagogical experience was created for the fifth, sixth and seventh cohorts of the Master\'s Degree in Museology and Heritage Management at the National University of Colombia, the name of the course is, ... to no one\'s surprise \ud83d\ude0c, INFORMATION TECHNOLOGIES AND VIRTUAL ENVIRONMENTS.\\n\\nThis course was shared with other teachers, in the first cohorts it was taught together with Philippe Boland and Ana Mar\xeda Moreno Ballesteros. The course of the year 2021 I worked together with [Paola Parra](https://www.linkedin.com/in/paoltricia).\\n\\n[Click here to see the course program (in spanish)](./program-mmgp-jcarroyos-paoltricia.pdf)\\n\\n## Class pics\\n\\n![registro de clase mmgp](./mmgp-1.jpg)\\n![registro de clase mmgp](./mmgp-2.jpg)\\n![registro de clase mmgp](./mmgp-3.jpg)\\n![registro de clase mmgp](./mmgp-4.jpg)"},{"id":"infographics-utolima","metadata":{"permalink":"/portfolio/es/blog/infographics-utolima","source":"@site/blog/2021-01-30-infographics/index.md","title":"Infographics at UTolima","description":"Since","date":"2021-01-30T00:00:00.000Z","formattedDate":"30 de enero de 2021","tags":[{"label":"infographics","permalink":"/portfolio/es/blog/tags/infographics"}],"readingTime":0.235,"hasTruncateMarker":false,"authors":[{"name":"Juan Carlos","title":"Arroyo Sosa","url":"https://github.com/jcarroyos","imageURL":"https://avatars.githubusercontent.com/u/4398275","key":"jcarroyos"}],"frontMatter":{"slug":"infographics-utolima","title":"Infographics at UTolima","authors":["jcarroyos"],"tags":["infographics"]},"prevItem":{"title":"Virtual enviroments at MMGP","permalink":"/portfolio/es/blog/virtual-enviroment-unal"}},"content":"Since\\nWith a practical approach, this course presents the evolution of infographics, the workshop focus on the core questions:\\n\\n- what is infographics?\\n- what are infographics for?\\n- and how we can made infographics?\\n\\n:::tip\\n\\nUse the power of React to create interactive blog posts.\\n\\n:::"}]}')}}]);